import React, { useState } from 'react';
import axios from 'axios';

function Review({ review, bookId, api_url, onReviewDeleted, onReviewEdited }) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedName, setEditedName] = useState(review.name);
  const [editedComment, setEditedComment] = useState(review.comment);
  const [editedRating, setEditedRating] = useState(review.rating);
  const [isDeleting, setIsDeleting] = useState(false);

  const handleDelete = async () => {
    const userConfirmed = window.confirm('Are you sure you want to delete this review?');
    if (!userConfirmed) return;

    setIsDeleting(true);
    try {
      await axios.delete(`${api_url}/books/${bookId}/reviews/${review.id}`);
      onReviewDeleted(review.id);
    } catch (error) {
      console.error('Error deleting review:', error);
    } finally {
      setIsDeleting(false);
    }
  };

  const handleEdit = async () => {
    try {
      const response = await axios.put(`${api_url}/books/${bookId}/reviews/${review.id}`, {
        name: editedName,
        comment: editedComment,
        rating: parseInt(editedRating),
      });
      onReviewEdited(response.data);
      setIsEditing(false);
    } catch (error) {
      console.error('Error editing review:', error);
    }
  };

  if (isEditing) {
    return (
      <div className="bg-gray-50 rounded-xl p-6 shadow-md">
        <input
          type="text"
          value={editedName}
          onChange={(e) => setEditedName(e.target.value)}
          className="w-full mb-2 p-2 border border-gray-300 rounded"
        />
        <textarea
          value={editedComment}
          onChange={(e) => setEditedComment(e.target.value)}
          className="w-full mb-2 p-2 border border-gray-300 rounded"
          rows="3"
        />
        <select
          value={editedRating}
          onChange={(e) => setEditedRating(e.target.value)}
          className="w-full p-2 border border-gray-300 rounded"
        >
          {[1, 2, 3, 4, 5].map(star => <option key={star} value={star}>{star} Star{star > 1 && 's'}</option>)}
        </select>
        <div className="flex justify-end mt-4 space-x-2">
          <button
            onClick={handleEdit}
            className="bg-green-500 text-white px-4 py-2 rounded-full hover:bg-green-600 transition-colors"
          >
            Save
          </button>
          <button
            onClick={() => setIsEditing(false)}
            className="bg-gray-500 text-white px-4 py-2 rounded-full hover:bg-gray-600 transition-colors"
          >
            Cancel
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl p-6 shadow-md border-l-4 border-gray-400">
      <div className="flex justify-between items-center mb-2">
        <p className="text-xl font-semibold text-gray-800">{review.name}</p>
        <div className="flex items-center text-sm text-yellow-500">
          {'★'.repeat(review.rating)}{'☆'.repeat(5 - review.rating)}
        </div>
      </div>
      <p className="text-gray-700 leading-relaxed mb-4">{review.comment}</p>
      <div className="flex justify-end space-x-2">
        <button
          onClick={() => setIsEditing(true)}
          className="bg-blue-500 text-white px-4 py-2 rounded-full hover:bg-blue-600 transition-colors font-semibold text-sm"
        >
          Edit
        </button>
        <button
          onClick={handleDelete}
          disabled={isDeleting}
          className="bg-red-500 text-white px-4 py-2 rounded-full hover:bg-red-600 transition-colors font-semibold text-sm disabled:opacity-50"
        >
          {isDeleting ? 'Deleting...' : 'Delete'}
        </button>
      </div>
    </div>
  );
}

export default Review;
